import json, subprocess, time

NOTION_TOKEN = "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"
PAGE_ID = "35aa87b2e9a081a580ffda4e287f3121"

# Create new ESERCIZI PPL database
db_payload = {
    "parent": {"page_id": PAGE_ID},
    "title": [{"text": {"content": "🏋️ ESERCIZI PPL"}}],
    "properties": {
        "Exercise": {"title": {}},
        "Day": {
            "select": {
                "options": [
                    {"name": "Push A", "color": "red"},
                    {"name": "Pull A", "color": "blue"},
                    {"name": "Legs A", "color": "green"},
                    {"name": "Push B", "color": "orange"},
                    {"name": "Pull B", "color": "purple"},
                    {"name": "Legs B", "color": "yellow"},
                ]
            }
        },
        "Muscle Group": {
            "multi_select": {
                "options": [
                    {"name": "Petto", "color": "red"},
                    {"name": "Spalle", "color": "orange"},
                    {"name": "Tricipiti", "color": "pink"},
                    {"name": "Dorsali", "color": "blue"},
                    {"name": "Bicipiti", "color": "purple"},
                    {"name": "Quadricipiti", "color": "green"},
                    {"name": "Posteriori", "color": "brown"},
                    {"name": "Polpacci", "color": "yellow"},
                ]
            }
        },
        "Sets Target": {"number": {"format": "number"}},
        "Rep Target": {"rich_text": {}},
        "Rest": {
            "select": {
                "options": [
                    {"name": "30-45s (FST-7)", "color": "pink"},
                    {"name": "60-90s", "color": "default"},
                    {"name": "90s-2min", "color": "default"},
                    {"name": "2-3min", "color": "green"},
                    {"name": "3min", "color": "blue"},
                ]
            }
        },
        "Type": {
            "select": {
                "options": [
                    {"name": "Compound", "color": "red"},
                    {"name": "Isolation", "color": "blue"},
                    {"name": "FST-7 Finisher", "color": "pink"},
                    {"name": "Pre-activation", "color": "green"},
                ]
            }
        },
        "Notes": {"rich_text": {}}
    }
}

result = subprocess.run([
    'curl', '-s', '-X', 'POST',
    'https://api.notion.com/v1/databases',
    '-H', f'Authorization: Bearer {NOTION_TOKEN}',
    '-H', 'Notion-Version: 2022-06-28',
    '-H', 'Content-Type: application/json',
    '-d', json.dumps(db_payload)
], capture_output=True, text=True)

resp = json.loads(result.stdout)
if 'id' in resp:
    new_db_id = resp['id']
    print(f"Created new database: {new_db_id}")
else:
    print(f"Error: {resp}")
"}
